const u="TAVERNOS_LLM_STUB";export function isLlmStubEnabled(){return process.env[u]==="true"||process.env[u]==="1"}export function stubChatCompletion(t,e){const n=[...t].reverse().find(s=>s.role==="user"),o=t.find(s=>s.role==="system"),a=h((o?.content??"")+"|"+(n?.content??"")),c=p(n?.content??"",a),r=t.reduce((s,l)=>s+Math.ceil(l.content.length/4),0),i=Math.ceil(c.length/4);return{content:c,usage:{promptTokens:r,completionTokens:i,totalTokens:r+i}}}function p(t,e){const n=t.slice(0,80);return[`[STUB RESPONSE #${e}]`,"","This is a deterministic stub response generated by TavernOS LLM stub.","The stub was activated because TAVERNOS_LLM_STUB=true.","",`Input topic: ${n}...`,"","In production, this would be replaced by a real LLM API call.","The stub ensures tests are reproducible without API keys or network access."].join(`
`)}function h(t){let e=0;for(let n=0;n<t.length;n++){const o=t.charCodeAt(n);e=(e<<5)-e+o,e|=0}return Math.abs(e)}
